import React, { useState } from 'react';
import PremblyPass from 'prembly-pass';

function App() {
  const [attemptsRemaining, setAttemptsRemaining] = useState(3);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleStartVerification = () => {
    // Initialize PremblyPass with environment variables
    const prembly = new PremblyPass({
      app_id: import.meta.env.VITE_PREMBLY_APP_ID,
      x_api_key: import.meta.env.VITE_PREMBLY_API_KEY,
      environment: "test"
    });

    // Success event handler
    prembly.on('success', (data) => {
      console.log('Verification successful:', data);
      setIsSuccess(true);
    });

    // Error event handler
    prembly.on('error', (error) => {
      console.error('Verification failed:', error);
      setAttemptsRemaining((prev) => prev - 1);
    });

    // Launch the widget with the config ID
    prembly.launch(import.meta.env.VITE_PREMBLY_CONFIG_ID);
  };

  return (
    <div style={{ 
      display: 'flex', 
      flexDirection: 'column', 
      alignItems: 'center', 
      justifyContent: 'center', 
      height: '100vh',
      fontFamily: 'Arial, sans-serif'
    }}>
      <h1>Prembly Document Verification</h1>

      {isSuccess ? (
        <div style={{ textAlign: 'center' }}>
          <h2 style={{ color: 'green' }}>Verification successful!</h2>
        </div>
      ) : (
        <div style={{ textAlign: 'center' }}>
          {attemptsRemaining > 0 ? (
            <>
              <p>Attempts remaining: {attemptsRemaining}</p>
              <button 
                onClick={handleStartVerification}
                style={{
                  padding: '10px 20px',
                  fontSize: '16px',
                  cursor: 'pointer',
                  backgroundColor: '#007bff',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px'
                }}
              >
                Start Verification
              </button>
            </>
          ) : (
            <>
              <p style={{ color: 'red', fontWeight: 'bold' }}>
                Maximum retries exceeded. Please contact support.
              </p>
              <button 
                disabled 
                style={{
                  padding: '10px 20px',
                  fontSize: '16px',
                  cursor: 'not-allowed',
                  backgroundColor: '#ccc',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px'
                }}
              >
                Start Verification
              </button>
            </>
          )}
        </div>
      )}
    </div>
  );
}

export default App;

